import{_ as a,o as t,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"60. Annual Leave","description":"","frontmatter":{"title":"60. Annual Leave","eba":"Doctors in Training 2022-2026","topics":["leave","annual-leave","public-holidays","employment"]},"headers":[],"relativePath":"ebas/doctors-in-training/leave/60-annual-leave.md","filePath":"ebas/doctors-in-training/leave/60-annual-leave.md"}'),r={name:"ebas/doctors-in-training/leave/60-annual-leave.md"};function s(i,e,l,c,h,u){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_60-annual-leave" tabindex="-1">60. Annual Leave <a class="header-anchor" href="#_60-annual-leave" aria-label="Permalink to &quot;60. Annual Leave&quot;">​</a></h1><p><strong>60.1</strong> Entitlement</p><p><strong>(a)</strong> A full-time or part-time Doctor is entitled to paid annual leave as follows:</p><p><strong>(i)</strong> 5 weeks if the Doctor is a Shiftworker (as defined in <a href="/eba/ebas/doctors-in-training/preliminary/3-definitions.html">clause 3</a>, as a Doctor required to work in excess of their ordinary hours, or works ordinary hours on more than 10 weekends (defined as a Saturday or Sunday or both) during the leave accrual year); or</p><p><strong>(ii)</strong> 4 weeks if subclause 60.1(a)(i) does not apply.</p><p><strong>(b)</strong> If the period during which a Doctor takes paid annual leave includes a day or part- day that is a public holiday in the place where the Doctor is based for work purposes, the Doctor is taken not to be on paid annual leave on that public holiday.</p><p><strong>60.2</strong> Time of Taking Annual Leave</p><p><strong>(a)</strong> Paid annual leave may be taken for a period agreed between a Doctor and his or her Health Service.</p><p><strong>(b)</strong> The Doctor will submit a written request for annual leave at least 6 weeks prior to the first day of the proposed leave period/s unless it is not reasonable to do so in the circumstances.</p><p><strong>(c)</strong> Within 14 days of the leave request, the Health Service will notify the Doctor in writing that their annual leave request is approved or, if not approved, the reasons for the leave not being approved.</p><p><strong>(d)</strong> Where it is likely the leave request will be rejected, the Health Service and Doctor will consult on alternative leave days within the 10 day period.</p><p><strong>(e)</strong> The Health Service must not unreasonably refuse to agree to a request by the Doctor to take paid annual leave.</p><p><strong>(f)</strong> Once annual leave is approved, it must not be unilaterally changed by the Health Service. Where extraordinary circumstances arise, such that the Health Service wishes the Doctor to change the timing of their approved leave, any change may only occur through consultation and agreement.</p><p><strong>(g)</strong> Notwithstanding the above and subject to subclause 60.2(h), the Health Service may propose its preferred timing for the taking of Annual Leave by a Doctor (by way of posting within the roster or otherwise in writing to Doctor) to suit operational requirements and to ensure all Doctors are given adequate opportunity to utilise their Annual Leave within the year in which it is accrued.</p><p><strong>(h)</strong> A Doctor may request annual leave at a time other than as proposed by the Health Service in accordance with subclauses 60.2(a) to (f) above.</p><p><strong>(i)</strong> An HMO year 1 (Intern) may take up to 4 weeks of annual leave after 3 months of employment. All or part of the leave may be taken sooner if agreed.</p><p><strong>(j)</strong> A Doctor with more than one year of experience may take annual leave during or after the year in which their entitlement accrues.</p><p><strong>(k)</strong> If during a period of paid annual leave a Doctor is absent due to Personal Leave (subclause 61.1(a)) or Compassionate Leave (subclause 64.1(a)), the Doctor is entitled to be taken not to be on paid annual leave for that period and is entitled to instead access any paid entitlement the Doctor may have under <a href="/eba/ebas/doctors-in-training/leave/61-personal-sick-carer-s-leave.html">clauses 61</a> or 64 (as applicable).</p><p><strong>60.3</strong> Payment for Annual Leave</p><p>Prior to going on annual leave, the Doctor must be paid for the period of leave, unless otherwise agreed.</p><p><strong>60.4</strong> Annual leave in advance</p><p><strong>(a)</strong> A Health Service and Doctor may agree in writing to the Doctor taking a period of paid annual leave before the employee has accrued an entitlement to the leave.</p><p><strong>(b)</strong> An agreement must state the amount of leave to be taken in advance and the date on which leave is to commence</p><p>NOTE: An example of the type of agreement required by clause 60.4 is set out at requirement to use the form of agreement set out at <a href="/eba/ebas/doctors-in-training/appendices/4-agreement-to-take-annual-leave-in-advance.html">Appendix 4</a> Agreement to Take Annual Leave in Advance.</p><p><strong>(c)</strong> The Health Service must keep a copy of any agreement under clause 60.4 as a record.</p><p><strong>(d)</strong> If, on the termination of the Doctor’s employment, the Doctor has not accrued an entitlement to all of a period of paid annual leave already taken in accordance with an agreement under clause 60.4, the Health Service may deduct from any money due to the Doctor on termination an amount equal to the amount that was paid to</p><p>the Doctor in respect of any part of the period of annual leave taken in advance to which an entitlement has not been accrued.</p><p><strong>60.5</strong> Cashing out of annual leave</p><p><strong>(a)</strong> Paid annual leave must not be cashed out except in accordance with an agreement under clause 60.5.</p><p><strong>(b)</strong> Each cashing out of a particular amount of paid annual leave must be the subject of a separate agreement under clause 60.5.</p><p><strong>(c)</strong> A Health Service and a Doctor may agree in writing to the cashing out of a particular amount of accrued paid annual leave by the employee.</p><p><strong>(d)</strong> An agreement under clause 60.5 must state:</p><p><strong>(i)</strong> the amount of leave to be cashed out and the payment to be made to the Doctor for it; and</p><p><strong>(ii)</strong> the date on which the payment is to be made.</p><p><strong>(e)</strong> An agreement under clause 60.5 must be signed by the Health Service.</p><p><strong>(f)</strong> The payment must not be less than the amount that would have been payable had the Doctor taken the leave at the time the payment is made.</p><p><strong>(g)</strong> An agreement must not result in the Doctor’s remaining accrued entitlement to paid annual leave being less than 10 weeks.</p><p><strong>(h)</strong> The maximum amount of accrued paid annual leave that may be cashed out in any period of 12 months is 2 weeks.</p><p><strong>(i)</strong> The Health Service must keep a copy of any agreement under clause 60.5 as an employee record.</p><p>NOTE 1: Under section 344 of the Act, an employer must not exert undue influence or undue pressure on an employee to make, or not make, an agreement under clause 60.5.</p><p>NOTE 2: Under section 345(1) of the Act, a person must not knowingly or recklessly make a false or misleading representation about the workplace rights of another person under clause 60.5.</p><p>NOTE 3: An example of the type of agreement required by clause 60.5 is set out at of agreement set out at <a href="/eba/ebas/doctors-in-training/appendices/5-agreement-to-cash-out-annual-leave.html">Appendix 5</a>—Agreement to Cash Out Annual Leave.</p><p><strong>60.6</strong> Excessive annual leave accruals: general provision</p><p><strong>(a)</strong> A doctor has an excessive leave accrual if:</p><p><strong>(i)</strong> prior to 1 January 2023, the Doctor has accrued more than 15 weeks’ paid annual leave having regard to their current fraction; or</p><p><strong>(ii)</strong> on or after 1 January 2023, the Doctor has accrued more than 10 weeks’ paid annual leave having regard to their current fraction.</p><p><strong>(b)</strong> If a Doctor has an excessive leave accrual, the Health Service or the Doctor may seek to confer with the other and genuinely try to reach agreement on how to reduce or eliminate the excessive leave accrual.</p><p><strong>(c)</strong> Clause 60.7 sets out how a Health Service may direct a Doctor who has an excessive annual leave accrual to take paid annual leave.</p><p><strong>(d)</strong> Clause 60.8 sets out how a Doctor who has an excessive leave accrual may require a Health Service to grant paid annual leave requested by the Doctor.</p><p><strong>60.7</strong> Excessive annual leave accruals: Managing excess leave</p><p><strong>(a)</strong> If a Health Service has genuinely tried to reach agreement with a Doctor under clause 60.6(b) but agreement is not reached (including because the Doctor refuses to confer), the Health Service may require the Doctor by a notice in writing to take one or more periods of paid annual leave. Any discussions should take into account the Doctor’s workload and the availability of suitable relief staff.</p><p><strong>(b)</strong> However, the requirement by the Health Service under clause 60.7(a):</p><p><strong>(i)</strong> is of no effect if the doctor has made a request for leave in accordance with subclause 60.7 and such request has been declined in the previous 12 months; and</p><p><strong>(ii)</strong> is of no effect if it would result at any time in the Doctor’s remaining accrued entitlement to paid annual leave being less than 6 weeks when any other paid annual leave arrangements (whether made under 60.6, 60.7, or 60.8 or otherwise agreed by the Health Service and Doctor) are taken into account; and</p><p><strong>(iii)</strong> must not require the Doctor to take any period of paid annual leave of less than one week; and</p><p><strong>(iv)</strong> must not require the Doctor to take a period of paid annual leave beginning less than 8 weeks, or more than 12 months, after the direction is given; and</p><p><strong>(v)</strong> must not be inconsistent with any leave arrangement agreed by the Health Service and Doctor.</p><p><strong>(c)</strong> The Doctor must take paid annual leave in accordance with a notice under clause 60.6(a) that is in effect.</p><p><strong>(d)</strong> A Doctor to whom a notice has been given under clause 60.7(a) may request to take a period of paid annual leave as if the notice had not been given.</p><p>NOTE 1: Paid annual leave arising from a request mentioned in clause 60.7(d) may result in the direction ceasing to have effect. See clause 60.7(b)(i).</p><p>NOTE 2: Under section 88(2) of the Act, the Health Service must not unreasonably refuse to agree to a request by the Doctor to take paid annual leave.</p><p><strong>60.8</strong> Excessive annual leave accruals: request by Doctor for leave</p><p><strong>(a)</strong> If a Doctor has genuinely tried to reach agreement with a Health Service under clause 60.6(b) but agreement is not reached (including because the Health Service refuses to confer), the Doctor may give a written notice to the Health Service requesting to take one or more periods of paid annual leave.</p><p><strong>(b)</strong> However, a Doctor may only give a notice to the Health Service under clause 60.8(a) if:</p><p><strong>(i)</strong> the Doctor has had an excessive leave accrual for more than 3 months at the time of giving the notice; and</p><p><strong>(ii)</strong> the Doctor has not been given a direction under clause 60.7(a) that, when any other paid annual leave arrangements (whether made under clause 60.6, 60.7 or 60.8 or otherwise agreed by the Health Service and</p><p>Doctor) are taken into account, would eliminate the Doctor’s excessive leave accrual.</p><p><strong>(c)</strong> A notice given by a Doctor under clause 60.7(a) must not:</p><p><strong>(i)</strong> if granted, result in the employee’s remaining accrued entitlement to paid annual leave being at any time less than 6 weeks when any other paid annual leave arrangements (whether made under clause 60.6, 60.7 or</p><p><strong>60.8</strong> or otherwise agreed by the Health Service and Doctor) are taken into account; or</p><p><strong>(ii)</strong> provide for the Doctor to take any period of paid annual leave of less than one week; or</p><p><strong>(iii)</strong> provide for the Doctor to take a period of paid annual leave beginning less than 8 weeks, or more than 12 months, after the notice is given; or</p><p><strong>(iv)</strong> be inconsistent with any leave arrangement agreed by the Health Service and Doctor.</p><p><strong>(d)</strong> A Doctor is not entitled to request by a notice under clause 60.8(a) more than 5 weeks’ paid annual leave in any period of 12 months.</p><p><strong>(e)</strong> The Health Service must grant paid annual leave requested by a notice under clause 60.8(a).</p><p><strong>60.9</strong> Effect of Other Leave</p><p>If the period during which a Doctor takes paid annual leave includes a period of any other approved leave (including personal/carer&#39;s leave), other than unpaid parental leave or community service leave, the Doctor is taken not to be on paid annual leave for the period of that other leave.</p><p><strong>60.10</strong> Effect of Termination</p><p>Where the Doctor’s employment with a Health Service is terminated, the Doctor must be paid in lieu of any untaken accrued annual leave. Pro-rata payment shall be made if the Doctor has been employed for less than 12 months.</p><p>Plain language terms: holidays, vacation.</p>',80)])])}const g=a(r,[["render",s]]);export{d as __pageData,g as default};
